"use strict";parserFactory.register("wordexcerpt.com",()=>new WordexcerptParser);class WordexcerptParser extends Parser{constructor(){super()}getChapterUrls(e){let t=e.querySelector("div.listing-chapters_wrap");return Promise.resolve(util.hyperlinksToChapterList(t).reverse())}findContent(e){return e.querySelector("div.reading-content div.text-left")}extractTitleImpl(e){return e.querySelector("div.post-title h1")}extractAuthor(e){let t=e.querySelector("div.author-content a");return null===t?super.extractAuthor(e):t.textContent}removeUnwantedElementsFromContentElement(e){let t=[...e.querySelectorAll("div.adsbyvli")].map(e=>e.parentElement).filter(e=>"CENTER"===e.tagName.toUpperCase());util.removeElements(t);for(let t of util.getElements(e,"B:IF"))util.flattenNode(t);super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("ol.breadcrumb li.active").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.summary_image")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.summary__content p")]}}